import{_ as i,c as a,o as e,ah as o}from"./chunks/framework.Cnj7lwEt.js";const u=JSON.parse('{"title":"项目名称","description":"","frontmatter":{},"headers":[],"relativePath":"github汇总/视频工具/Douyin_TikTok_Download_API-视频工具.md","filePath":"github汇总/视频工具/Douyin_TikTok_Download_API-视频工具.md"}'),r={name:"github汇总/视频工具/Douyin_TikTok_Download_API-视频工具.md"};function t(n,l,d,h,s,c){return e(),a("div",null,l[0]||(l[0]=[o('<h1 id="项目名称" tabindex="-1">项目名称 <a class="header-anchor" href="#项目名称" aria-label="Permalink to “项目名称”">​</a></h1><p>Douyin_TikTok_Download_API</p><h1 id="作者或组织名" tabindex="-1">作者或组织名 <a class="header-anchor" href="#作者或组织名" aria-label="Permalink to “作者或组织名”">​</a></h1><p>Evil0ctal</p><h1 id="项目类别" tabindex="-1">项目类别 <a class="header-anchor" href="#项目类别" aria-label="Permalink to “项目类别”">​</a></h1><p>视频工具</p><h1 id="核心痛点" tabindex="-1">核心痛点 <a class="header-anchor" href="#核心痛点" aria-label="Permalink to “核心痛点”">​</a></h1><p>需要一个能够下载抖音和TikTok无水印视频的工具，同时提供API接口方便开发者集成。</p><h1 id="主要功能" tabindex="-1">主要功能 <a class="header-anchor" href="#主要功能" aria-label="Permalink to “主要功能”">​</a></h1><ul><li>Web端批量解析抖音和TikTok视频链接</li><li>在线下载无水印视频或图集</li><li>提供丰富的API接口</li><li>支持iOS快捷指令无水印下载</li><li>数据爬取API</li></ul><h1 id="项目亮点" tabindex="-1">项目亮点 <a class="header-anchor" href="#项目亮点" aria-label="Permalink to “项目亮点”">​</a></h1><ul><li>基于PyWebIO、FastAPI、HTTPX，快速异步</li><li>使用X-Bogus算法和A-Bogus算法应对平台风控</li><li>提供多种部署方式：一键部署脚本和Docker部署</li><li>支持批量解析和下载</li><li>开源免费，采用Apache-2.0许可证</li></ul><h1 id="荣誉信息" tabindex="-1">荣誉信息 <a class="header-anchor" href="#荣誉信息" aria-label="Permalink to “荣誉信息”">​</a></h1><p>README/仓库信息中未明确说明</p><h1 id="项目地址" tabindex="-1">项目地址 <a class="header-anchor" href="#项目地址" aria-label="Permalink to “项目地址”">​</a></h1><p><a href="https://github.com/Evil0ctal/Douyin_TikTok_Download_API" target="_blank" rel="noreferrer">https://github.com/Evil0ctal/Douyin_TikTok_Download_API</a> <a href="/网络环境.html">海外网络环境配置 →</a></p><h1 id="安装或部署教程" tabindex="-1">安装或部署教程 <a class="header-anchor" href="#安装或部署教程" aria-label="Permalink to “安装或部署教程”">​</a></h1><h2 id="教程适用对象与环境范围" tabindex="-1">教程适用对象与环境范围 <a class="header-anchor" href="#教程适用对象与环境范围" aria-label="Permalink to “教程适用对象与环境范围”">​</a></h2><p>适用于需要下载抖音和TikTok无水印视频的用户，支持Linux和Docker环境。</p><h2 id="前置条件检查" tabindex="-1">前置条件检查 <a class="header-anchor" href="#前置条件检查" aria-label="Permalink to “前置条件检查”">​</a></h2><ol><li>系统要求：Linux系统（推荐Ubuntu 20.04 LTS）或安装了Docker的系统</li><li>网络要求：能够访问抖音和TikTok</li><li>权限要求：有足够的权限执行部署脚本或管理Docker容器</li></ol><h2 id="主路径-安装与启动" tabindex="-1">主路径：安装与启动 <a class="header-anchor" href="#主路径-安装与启动" aria-label="Permalink to “主路径：安装与启动”">​</a></h2><h3 id="方式一-linux一键部署" tabindex="-1">方式一：Linux一键部署 <a class="header-anchor" href="#方式一-linux一键部署" aria-label="Permalink to “方式一：Linux一键部署”">​</a></h3><ol><li><p><strong>下载并运行安装脚本</strong></p><ul><li>执行位置：Linux终端</li><li>完整命令：<code>wget -O install.sh https://raw.githubusercontent.com/Evil0ctal/Douyin_TikTok_Download_API/main/bash/install.sh &amp;&amp; sudo bash install.sh</code></li><li>成功标志：脚本执行完成，服务启动成功</li><li>失败处理：检查网络连接，确保系统满足要求</li></ul></li><li><p><strong>控制服务</strong></p><ul><li>启动服务：<code>sudo systemctl start Douyin_TikTok_Download_API.service</code></li><li>停止服务：<code>sudo systemctl stop Douyin_TikTok_Download_API.service</code></li><li>设置开机自启：<code>sudo systemctl enable Douyin_TikTok_Download_API.service</code></li><li>取消开机自启：<code>sudo systemctl disable Douyin_TikTok_Download_API.service</code></li></ul></li><li><p><strong>更新项目</strong></p><ul><li>执行位置：项目bash目录</li><li>完整命令：<code>cd /www/wwwroot/Douyin_TikTok_Download_API/bash &amp;&amp; sudo bash update.sh</code></li><li>成功标志：更新完成，服务重启成功</li><li>失败处理：检查网络连接，确保虚拟环境正常</li></ul></li></ol><h3 id="方式二-docker部署" tabindex="-1">方式二：Docker部署 <a class="header-anchor" href="#方式二-docker部署" aria-label="Permalink to “方式二：Docker部署”">​</a></h3><ol><li><p><strong>拉取Docker镜像</strong></p><ul><li>执行位置：终端</li><li>完整命令：<code>docker pull evil0ctal/douyin_tiktok_download_api:latest</code></li><li>成功标志：镜像拉取完成，无错误信息</li><li>失败处理：检查Docker是否正常运行，网络连接是否通畅</li></ul></li><li><p><strong>运行Docker容器</strong></p><ul><li>执行位置：终端</li><li>完整命令：<code>docker run -d --name douyin_tiktok_api -p 80:80 evil0ctal/douyin_tiktok_download_api</code></li><li>成功标志：容器启动成功，无错误信息</li><li>失败处理：检查端口是否被占用，Docker是否正常运行</li></ul></li><li><p><strong>验证容器运行状态</strong></p><ul><li>执行位置：终端</li><li>完整命令：<code>docker ps</code></li><li>成功标志：容器状态为运行中</li><li>失败处理：查看容器日志，排查错误原因</li></ul></li><li><p><strong>停止并移除容器</strong></p><ul><li>停止容器：<code>docker stop douyin_tiktok_api</code></li><li>移除容器：<code>docker rm douyin_tiktok_api</code></li></ul></li></ol><h2 id="配置文件修改" tabindex="-1">配置文件修改 <a class="header-anchor" href="#配置文件修改" aria-label="Permalink to “配置文件修改”">​</a></h2><p>项目的大部分配置可以在以下几个目录中的config.yaml文件进行修改：</p><ul><li>/crawlers/douyin/web/config.yaml</li><li>/crawlers/tiktok/web/config.yaml</li><li>/crawlers/tiktok/app/config.yaml</li></ul><h2 id="安装成功验证" tabindex="-1">安装成功验证 <a class="header-anchor" href="#安装成功验证" aria-label="Permalink to “安装成功验证”">​</a></h2><ul><li>访问地址：<a href="http://localhost" target="_blank" rel="noreferrer">http://localhost</a> 或 <a href="http://xn--IP-fr5c86lx7z" target="_blank" rel="noreferrer">http://服务器IP</a></li><li>预期返回：Web界面或API文档</li></ul><h2 id="常见错误排查" tabindex="-1">常见错误排查 <a class="header-anchor" href="#常见错误排查" aria-label="Permalink to “常见错误排查”">​</a></h2><ol><li><p><strong>API无法使用</strong></p><ul><li>现象：API返回错误或无响应</li><li>可能原因：Cookie过期或风控</li><li>解决步骤：获取新的Cookie并更新配置文件</li></ul></li><li><p><strong>Docker容器启动失败</strong></p><ul><li>现象：执行docker run命令后容器状态为exited</li><li>可能原因：端口被占用、配置错误</li><li>解决步骤：检查端口占用情况，修改端口映射</li></ul></li><li><p><strong>TikTok视频下载失败</strong></p><ul><li>现象：TikTok视频无法下载</li><li>可能原因：直接访问TikTok视频链接会出现HTTP 403错误</li><li>解决步骤：使用项目API中的/api/download接口进行下载</li></ul></li></ol><h2 id="备选部署路径" tabindex="-1">备选部署路径 <a class="header-anchor" href="#备选部署路径" aria-label="Permalink to “备选部署路径”">​</a></h2><p>README/仓库信息中未提供其他部署方式。</p><h2 id="信息缺失说明" tabindex="-1">信息缺失说明 <a class="header-anchor" href="#信息缺失说明" aria-label="Permalink to “信息缺失说明”">​</a></h2><p>README/仓库信息中未提供完整的配置选项说明，上述教程基于README中提到的部署方式整理。</p>',37)]))}const _=i(r,[["render",t]]);export{u as __pageData,_ as default};
